import { act, fireEvent, render, screen, waitFor, within } from "@testing-library/react";
import { beforeEach, describe, expect, it, vi } from "vitest";
import type { TerminalOutputEvent } from "../lib/terminalApi";
import { defaultAppSettings } from "../features/settings/settingsModel";
import {
  resetWorkspaceStore,
  useWorkspaceStore,
} from "../features/workspace/workspaceStore";
import {
  getKerminalShellTestMocks,
  mockElementFromPoint,
  remoteHostTree,
} from "./KerminalShell.testSupport";
import { KerminalShell } from "./KerminalShell";

const mocks = getKerminalShellTestMocks();

async function findExpandedSidebarMachine(name: RegExp) {
  const sidebar = screen.getByRole("complementary", { name: "主机侧边栏" });
  await screen.findByRole("button", { name: /bwy/i });

  let machineButton = within(sidebar).queryByRole("button", { name });
  if (machineButton) {
    return machineButton;
  }

  for (const groupButton of within(sidebar).queryAllByRole("button")) {
    if (groupButton.getAttribute("aria-expanded") === "false") {
      fireEvent.click(groupButton);
    }
  }

  return within(sidebar).findByRole("button", { name });
}

describe("KerminalShell sidebar split drop", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    document.documentElement.classList.remove("dark");
    document.documentElement.removeAttribute("data-theme");
    window.localStorage.clear();
    resetWorkspaceStore();
    mocks.nativeMenuApi.listenNativeMenuActions.mockResolvedValue(
      () => undefined,
    );
    mocks.profileApi.listProfiles.mockResolvedValue([]);
    mocks.remoteHostApi.listRemoteHostTree.mockResolvedValue(remoteHostTree);
    mocks.settingsApi.getSettings.mockResolvedValue(defaultAppSettings);
    mocks.settingsApi.updateSettings.mockImplementation(
      async (settings) => settings,
    );
    mocks.terminalApi.createTerminalSession.mockImplementation(
      async (_request, onOutput: (event: TerminalOutputEvent) => void) => {
        onOutput({
          data: "local ready",
          kind: "data",
          sessionId: "session-local",
        });
        return {
          cols: 80,
          id: "session-local",
          rows: 24,
          shell: "test-shell",
          status: "running",
        };
      },
    );
    mocks.terminalApi.createSshTerminalSession.mockImplementation(
      async (_request, onOutput: (event: TerminalOutputEvent) => void) => {
        onOutput({
          data: "ssh ready",
          kind: "data",
          sessionId: "session-ssh",
        });
        return {
          cols: 80,
          id: "session-ssh",
          rows: 24,
          shell: "ssh",
          status: "running",
        };
      },
    );
    mocks.terminalApi.getTerminalLogState.mockResolvedValue({
      active: false,
      bytesWritten: 0,
    });
  });

  it("splits the focused terminal to a dropped sidebar host", async () => {
    render(<KerminalShell />);

    const hostButton = await findExpandedSidebarMachine(/172\.16\.41\.60/);

    act(() => {
      useWorkspaceStore.getState().addTerminalTab();
    });
    await waitFor(() => {
      expect(mocks.terminalApi.createTerminalSession).toHaveBeenCalled();
    });

    const terminalContent = document.querySelector<HTMLElement>(
      "[data-terminal-workspace-content]",
    );
    expect(terminalContent).toBeInTheDocument();
    const rectSpy = vi.spyOn(terminalContent!, "getBoundingClientRect");
    rectSpy.mockReturnValue({
      bottom: 680,
      height: 600,
      left: 200,
      right: 1000,
      top: 80,
      width: 800,
      x: 200,
      y: 80,
      toJSON: () => ({}),
    } as DOMRect);
    const restoreElementFromPoint = mockElementFromPoint(document.body);

    try {
      fireEvent.pointerDown(hostButton, {
        button: 0,
        clientX: 16,
        clientY: 16,
        pointerId: 1,
      });
      fireEvent.pointerMove(window, {
        clientX: 980,
        clientY: 320,
        pointerId: 1,
      });

      expect(
        screen.getByRole("status", { name: "主机分屏拖放目标：右侧" }),
      ).toHaveTextContent("分屏到右侧 · 172.16.41.60");

      fireEvent.pointerUp(window, {
        clientX: 980,
        clientY: 320,
        pointerId: 1,
      });

      await waitFor(() => {
        expect(
          useWorkspaceStore.getState().terminalPanes.some(
            (pane) =>
              pane.machineId === "db980b17-2ed0-44e5-b72a-6ecadf788439" &&
              pane.mode === "ssh",
          ),
        ).toBe(true);
      });
      expect(mocks.remoteHostApi.updateRemoteHost).not.toHaveBeenCalled();
    } finally {
      rectSpy.mockRestore();
      restoreElementFromPoint();
    }
  });
});

import { fireEvent, render, screen } from "@testing-library/react";
import { describe, expect, it, vi } from "vitest";
import { MachineSidebar } from "./MachineSidebar";
import { mockElementFromPoint, remoteSidebarGroups } from "./MachineSidebar.testSupport";

describe("MachineSidebar external drag target", () => {
  it("lets an external target consume a dragged machine without moving groups", () => {
    const onExternalMachineDrag = vi.fn(() => ({
      hint: "松开分屏到右侧",
    }));
    const onExternalMachineDragEnd = vi.fn();
    const onExternalMachineDrop = vi.fn(() => true);
    const onMoveMachine = vi.fn();
    const restoreElementFromPoint = mockElementFromPoint(document.body);

    try {
      render(
        <MachineSidebar
          groups={remoteSidebarGroups}
          onExternalMachineDrag={onExternalMachineDrag}
          onExternalMachineDragEnd={onExternalMachineDragEnd}
          onExternalMachineDrop={onExternalMachineDrop}
          onMoveMachine={onMoveMachine}
          onSearchChange={vi.fn()}
          onSelectMachine={vi.fn()}
          search=""
          selectedMachineId="ubuntu-dev"
        />,
      );

      fireEvent.click(screen.getByRole("button", { name: "展开所有分组" }));
      fireEvent.pointerDown(screen.getByRole("button", { name: /ubuntu-dev/i }), {
        button: 0,
        clientX: 12,
        clientY: 12,
        pointerId: 1,
      });
      fireEvent.pointerMove(window, {
        clientX: 120,
        clientY: 48,
        pointerId: 1,
      });

      expect(screen.getByRole("status", { name: "正在拖动主机" })).toHaveTextContent(
        "松开分屏到右侧",
      );

      fireEvent.pointerUp(window, {
        clientX: 120,
        clientY: 48,
        pointerId: 1,
      });

      expect(onExternalMachineDrag).toHaveBeenCalledWith(
        expect.objectContaining({ clientX: 120, machine: expect.objectContaining({ id: "ubuntu-dev" }) }),
      );
      expect(onExternalMachineDrop).toHaveBeenCalledWith(
        expect.objectContaining({ clientY: 48, machine: expect.objectContaining({ id: "ubuntu-dev" }) }),
      );
      expect(onExternalMachineDragEnd).toHaveBeenCalled();
      expect(onMoveMachine).not.toHaveBeenCalled();
    } finally {
      restoreElementFromPoint();
    }
  });
});

import { AlertTriangle } from "lucide-react";
import { useEffect, useMemo, useRef, useState } from "react";
import { cn } from "../../lib/cn";
import type {
  BroadcastTargetMode,
  BroadcastTargetOption,
} from "./terminalBroadcastTargets";

interface TerminalBroadcastTargetSelectorProps {
  focusedPaneId: string;
  onTargetModeChange: (mode: BroadcastTargetMode) => void;
  onToggleCustomTarget: (paneId: string, selected: boolean) => void;
  productionTargetCount: number;
  selectedTargetPaneIds: string[];
  targetCount: number;
  targetMode: BroadcastTargetMode;
  targetOptions: BroadcastTargetOption[];
}

const modeLabels: Record<BroadcastTargetMode, string> = {
  all: "全部分屏",
  custom: "自定义",
  focused: "当前分屏",
};

function buildTargetSummaryLabel(
  mode: BroadcastTargetMode,
  targetCount: number,
  productionTargetCount: number,
) {
  const base =
    mode === "focused"
      ? modeLabels.focused
      : `${modeLabels[mode]} · ${targetCount}`;
  return productionTargetCount > 0
    ? `${base} · 生产 ${productionTargetCount}`
    : base;
}

function modeButtonClassName(active: boolean) {
  return cn(
    "kerminal-focus-ring kerminal-pressable flex w-full items-center justify-between rounded-xl px-3 py-2 text-left",
    active
      ? "bg-[var(--surface-selected)] text-sky-700 dark:text-sky-100"
      : "text-zinc-700 hover:bg-[var(--surface-hover)] hover:text-zinc-950 dark:text-zinc-200 dark:hover:text-zinc-50",
  );
}

export function TerminalBroadcastTargetSelector({
  focusedPaneId,
  onTargetModeChange,
  onToggleCustomTarget,
  productionTargetCount,
  selectedTargetPaneIds,
  targetCount,
  targetMode,
  targetOptions,
}: TerminalBroadcastTargetSelectorProps) {
  const [selectorOpen, setSelectorOpen] = useState(false);
  const selectorRef = useRef<HTMLDivElement>(null);
  const selectedTargetIds = useMemo(
    () => new Set(selectedTargetPaneIds),
    [selectedTargetPaneIds],
  );
  const focusedTarget = targetOptions.find(
    (target) => target.paneId === focusedPaneId,
  );
  const targetSummaryLabel = buildTargetSummaryLabel(
    targetMode,
    targetCount,
    productionTargetCount,
  );

  useEffect(() => {
    if (!selectorOpen) {
      return undefined;
    }

    const closeOnPointerDown = (event: PointerEvent) => {
      const target = event.target;
      if (!(target instanceof Node)) {
        return;
      }
      if (selectorRef.current?.contains(target)) {
        return;
      }
      setSelectorOpen(false);
    };
    const closeOnEscape = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        setSelectorOpen(false);
      }
    };
    window.addEventListener("pointerdown", closeOnPointerDown);
    window.addEventListener("keydown", closeOnEscape, true);
    return () => {
      window.removeEventListener("pointerdown", closeOnPointerDown);
      window.removeEventListener("keydown", closeOnEscape, true);
    };
  }, [selectorOpen]);

  const selectMode = (mode: BroadcastTargetMode) => {
    onTargetModeChange(mode);
    if (mode !== "custom") {
      setSelectorOpen(false);
    }
  };

  return (
    <div className="relative shrink-0" ref={selectorRef}>
      <button
        aria-expanded={selectorOpen}
        aria-haspopup="menu"
        aria-label={`发送目标：${targetSummaryLabel}`}
        className={cn(
          "kerminal-focus-ring kerminal-pressable flex h-9 items-center gap-1.5 rounded-xl border border-[var(--border-subtle)] bg-[var(--surface-hover)] px-2.5 text-xs font-medium text-zinc-700 shadow-sm shadow-black/5 transition-colors dark:text-zinc-200 dark:shadow-black/20",
          selectorOpen &&
            "border-sky-500/30 bg-[var(--surface-selected)] text-sky-700 dark:text-sky-100",
          productionTargetCount > 0 &&
            "border-amber-500/40 bg-amber-500/10 text-amber-700 dark:text-amber-200",
        )}
        onClick={() => setSelectorOpen((open) => !open)}
        title={`发送目标：${targetSummaryLabel}`}
        type="button"
      >
        {productionTargetCount > 0 ? (
          <AlertTriangle className="h-3.5 w-3.5" />
        ) : null}
        <span className="whitespace-nowrap">{targetSummaryLabel}</span>
      </button>

      {selectorOpen ? (
        <div
          aria-label="发送目标选择"
          className="kerminal-floating-enter absolute left-0 top-[calc(100%+0.5rem)] z-[1000] w-80 max-w-[calc(100vw-2rem)] rounded-2xl border border-[var(--border-subtle)] bg-[var(--surface-overlay)] p-2 text-sm shadow-2xl shadow-black/20 backdrop-blur-xl dark:shadow-black/50"
          role="menu"
        >
          <div className="space-y-1">
            <button
              aria-pressed={targetMode === "focused"}
              className={modeButtonClassName(targetMode === "focused")}
              disabled={!focusedTarget}
              onClick={() => selectMode("focused")}
              type="button"
            >
              <span>{modeLabels.focused}</span>
              <span className="text-xs text-zinc-500 dark:text-zinc-400">
                {focusedTarget ? focusedTarget.title : "无当前目标"}
              </span>
            </button>
            <button
              aria-pressed={targetMode === "all"}
              className={modeButtonClassName(targetMode === "all")}
              disabled={targetOptions.length === 0}
              onClick={() => selectMode("all")}
              type="button"
            >
              <span>{modeLabels.all}</span>
              <span className="text-xs text-zinc-500 dark:text-zinc-400">
                {targetOptions.length} 个目标
              </span>
            </button>
            <button
              aria-pressed={targetMode === "custom"}
              className={modeButtonClassName(targetMode === "custom")}
              disabled={targetOptions.length === 0}
              onClick={() => selectMode("custom")}
              type="button"
            >
              <span>{modeLabels.custom}</span>
              <span className="text-xs text-zinc-500 dark:text-zinc-400">
                {selectedTargetPaneIds.length} 个已选
              </span>
            </button>
          </div>

          <div className="mt-2 border-t border-[var(--border-subtle)] pt-2">
            <div className="mb-1.5 flex items-center justify-between px-1 text-xs text-zinc-500 dark:text-zinc-400">
              <span>分屏目标</span>
              {productionTargetCount > 0 ? (
                <span className="rounded-full border border-amber-500/30 bg-amber-500/10 px-2 py-0.5 font-medium text-amber-700 dark:text-amber-200">
                  生产 {productionTargetCount}
                </span>
              ) : null}
            </div>
            <div className="max-h-64 space-y-1 overflow-y-auto">
              {targetOptions.length > 0 ? (
                targetOptions.map((target) => (
                  <label
                    className={cn(
                      "kerminal-focus-ring flex cursor-pointer items-center gap-2 rounded-xl px-2.5 py-2",
                      selectedTargetIds.has(target.paneId)
                        ? "bg-[var(--surface-selected)]"
                        : "hover:bg-[var(--surface-hover)]",
                    )}
                    key={target.paneId}
                  >
                    <input
                      checked={selectedTargetIds.has(target.paneId)}
                      className="h-4 w-4 shrink-0"
                      onChange={(event) =>
                        onToggleCustomTarget(
                          target.paneId,
                          event.currentTarget.checked,
                        )
                      }
                      type="checkbox"
                    />
                    <span className="min-w-0 flex-1">
                      <span className="block truncate font-medium text-zinc-800 dark:text-zinc-100">
                        {target.title}
                      </span>
                      <span className="block truncate text-xs text-zinc-500 dark:text-zinc-400">
                        {target.subtitle}
                      </span>
                    </span>
                    <span className="rounded-md bg-[var(--surface-hover)] px-1.5 py-0.5 text-[10px] font-medium uppercase text-zinc-500 dark:text-zinc-400">
                      {target.mode}
                    </span>
                    {target.production ? (
                      <span className="rounded-md border border-amber-500/30 bg-amber-500/10 px-1.5 py-0.5 text-[10px] font-semibold uppercase text-amber-700 dark:text-amber-200">
                        生产
                      </span>
                    ) : null}
                  </label>
                ))
              ) : (
                <div className="rounded-xl bg-[var(--surface-hover)] px-3 py-2 text-sm text-zinc-500 dark:text-zinc-400">
                  没有可发送的真实终端分屏。
                </div>
              )}
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
}

import { cn } from "../../lib/cn";
import type { TerminalSplitDropZone } from "./terminalSplitDropZones";

export type TerminalSplitDropIndicator = {
  machineName: string;
  zone: TerminalSplitDropZone;
};

const dropZoneLabels: Record<TerminalSplitDropZone, string> = {
  bottom: "下方",
  left: "左侧",
  right: "右侧",
  top: "上方",
};

const baseZoneClassName =
  "absolute rounded-2xl border border-sky-300/35 bg-sky-500/10 transition-[opacity,background-color,box-shadow] duration-150 dark:border-sky-300/25 dark:bg-sky-300/10";
const idleZoneClassName = "opacity-45";
const activeZoneClassName =
  "opacity-100 shadow-[inset_0_0_0_2px_rgba(14,165,233,0.42),0_18px_55px_rgba(14,165,233,0.18)]";

export function TerminalSplitDropOverlay({
  indicator,
}: {
  indicator: TerminalSplitDropIndicator;
}) {
  const label = dropZoneLabels[indicator.zone];

  return (
    <div
      aria-label={`主机分屏拖放目标：${label}`}
      className="pointer-events-none absolute inset-0 z-30 rounded-2xl ring-2 ring-sky-400/30"
      role="status"
    >
      <div className="absolute left-1/2 top-4 z-10 max-w-[calc(100%-32px)] -translate-x-1/2 truncate rounded-full border border-sky-300/35 bg-[var(--surface-overlay)] px-3 py-1.5 text-xs font-medium text-sky-700 shadow-lg shadow-sky-950/10 backdrop-blur-xl dark:border-sky-300/20 dark:text-sky-100 dark:shadow-black/40">
        分屏到{label} · {indicator.machineName}
      </div>
      <DropZone active={indicator.zone === "left"} className="bottom-4 left-4 top-4 w-[18%]" />
      <DropZone active={indicator.zone === "right"} className="bottom-4 right-4 top-4 w-[18%]" />
      <DropZone active={indicator.zone === "top"} className="left-4 right-4 top-4 h-[22%]" />
      <DropZone active={indicator.zone === "bottom"} className="bottom-4 left-4 right-4 h-[22%]" />
    </div>
  );
}

function DropZone({ active, className }: { active: boolean; className: string }) {
  return (
    <div
      aria-hidden="true"
      className={cn(
        baseZoneClassName,
        active ? activeZoneClassName : idleZoneClassName,
        className,
      )}
    />
  );
}

import { Columns2, PanelBottom, Search } from "lucide-react";
import { useEffect, useMemo, useRef, useState } from "react";
import { Button } from "../../components/ui/button";
import { cn } from "../../lib/cn";
import type {
  MachineGroup,
  TerminalSplitDirection,
} from "../workspace/types";
import {
  createSplitTargetOptions,
  type SplitTargetOption,
  type TerminalSplitPaneOptions,
} from "./terminalSplitTargets";

interface TerminalSplitTargetSelectorProps {
  direction: TerminalSplitDirection;
  machineGroups: MachineGroup[];
  onSplitPane: (
    direction: TerminalSplitDirection,
    options?: TerminalSplitPaneOptions,
  ) => void;
}

const directionLabels: Record<TerminalSplitDirection, string> = {
  horizontal: "左右分屏",
  vertical: "上下分屏",
};

const kindLabels: Record<SplitTargetOption["kind"], string> = {
  dockerContainer: "container",
  local: "local",
  serial: "serial",
  ssh: "ssh",
  telnet: "telnet",
};

const statusDotClassNames: Record<SplitTargetOption["status"], string> = {
  offline: "bg-zinc-400",
  online: "bg-emerald-400",
  warning: "bg-amber-400",
};

function groupTargetsByGroup(targets: SplitTargetOption[]) {
  const groups: Array<{
    groupId: string;
    groupTitle: string;
    targets: SplitTargetOption[];
  }> = [];

  for (const target of targets) {
    const existing = groups.find((group) => group.groupId === target.groupId);
    if (existing) {
      existing.targets.push(target);
      continue;
    }
    groups.push({
      groupId: target.groupId,
      groupTitle: target.groupTitle,
      targets: [target],
    });
  }

  return groups;
}

function matchesSearch(target: SplitTargetOption, query: string) {
  const normalizedQuery = query.trim().toLowerCase();
  if (!normalizedQuery) {
    return true;
  }

  return [
    target.title,
    target.subtitle,
    target.hostLabel,
    target.groupTitle,
    target.kind,
  ].some((value) => value.toLowerCase().includes(normalizedQuery));
}

export function TerminalSplitTargetSelector({
  direction,
  machineGroups,
  onSplitPane,
}: TerminalSplitTargetSelectorProps) {
  const [selectorOpen, setSelectorOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const selectorRef = useRef<HTMLDivElement>(null);
  const splitLabel = directionLabels[direction];
  const targetOptions = useMemo(
    () => createSplitTargetOptions(machineGroups),
    [machineGroups],
  );
  const filteredTargets = useMemo(
    () => targetOptions.filter((target) => matchesSearch(target, searchQuery)),
    [searchQuery, targetOptions],
  );
  const targetGroups = useMemo(
    () => groupTargetsByGroup(filteredTargets),
    [filteredTargets],
  );

  useEffect(() => {
    if (!selectorOpen) {
      return undefined;
    }

    const closeOnPointerDown = (event: PointerEvent) => {
      const target = event.target;
      if (!(target instanceof Node)) {
        return;
      }
      if (selectorRef.current?.contains(target)) {
        return;
      }
      setSelectorOpen(false);
    };
    const closeOnEscape = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        setSelectorOpen(false);
      }
    };
    window.addEventListener("pointerdown", closeOnPointerDown);
    window.addEventListener("keydown", closeOnEscape, true);
    return () => {
      window.removeEventListener("pointerdown", closeOnPointerDown);
      window.removeEventListener("keydown", closeOnEscape, true);
    };
  }, [selectorOpen]);

  const splitCurrentTarget = () => {
    onSplitPane(direction);
  };

  const openTargetSelector = () => {
    if (targetOptions.length === 0) {
      return;
    }
    setSelectorOpen(true);
  };

  const splitTarget = (target: SplitTargetOption) => {
    onSplitPane(direction, { targetMachineId: target.id });
    setSelectorOpen(false);
    setSearchQuery("");
  };

  const Icon = direction === "horizontal" ? Columns2 : PanelBottom;

  return (
    <div className="relative shrink-0" ref={selectorRef}>
      <Button
        aria-expanded={selectorOpen}
        aria-haspopup="menu"
        aria-label={splitLabel}
        onClick={splitCurrentTarget}
        onContextMenu={(event) => {
          event.preventDefault();
          openTargetSelector();
        }}
        onKeyDown={(event) => {
          if (event.key === "ArrowDown" || event.key === "ContextMenu") {
            event.preventDefault();
            openTargetSelector();
          }
        }}
        size="icon"
        title={`${splitLabel}；右键选择主机`}
        variant="secondary"
      >
        <Icon className="h-4 w-4" />
      </Button>

      {selectorOpen ? (
        <div
          aria-label={`${splitLabel}目标选择`}
          className="kerminal-floating-enter absolute left-0 top-[calc(100%+0.5rem)] z-[1000] w-[22rem] max-w-[calc(100vw-2rem)] rounded-2xl border border-[var(--border-subtle)] bg-[var(--surface-overlay)] p-2 text-sm shadow-2xl shadow-black/20 backdrop-blur-xl dark:shadow-black/50"
          role="menu"
        >
          <div className="px-1 pb-2">
            <div className="text-sm font-medium text-zinc-950 dark:text-zinc-50">
              选择主机分屏
            </div>
            <div className="mt-0.5 text-xs text-zinc-500 dark:text-zinc-400">
              {splitLabel}到指定目标
            </div>
          </div>

          <label className="relative block">
            <span className="sr-only">搜索分屏主机</span>
            <Search className="pointer-events-none absolute left-3 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-zinc-400" />
            <input
              autoFocus
              className="kerminal-field-surface h-9 w-full rounded-xl border py-1 pl-8 pr-3 text-sm text-zinc-950 placeholder:text-zinc-400 dark:text-zinc-100 dark:placeholder:text-zinc-600"
              onChange={(event) => setSearchQuery(event.currentTarget.value)}
              placeholder="搜索主机、协议或分组"
              value={searchQuery}
            />
          </label>

          <div className="mt-2 max-h-72 space-y-2 overflow-y-auto">
            {targetGroups.length > 0 ? (
              targetGroups.map((group) => (
                <div key={group.groupId}>
                  <div className="px-1.5 py-1 text-xs font-medium text-zinc-500 dark:text-zinc-400">
                    {group.groupTitle}
                  </div>
                  <div className="space-y-1">
                    {group.targets.map((target) => (
                      <button
                        className="kerminal-focus-ring kerminal-pressable flex w-full items-center gap-2 rounded-xl px-2.5 py-2 text-left text-zinc-700 hover:bg-[var(--surface-hover)] hover:text-zinc-950 dark:text-zinc-200 dark:hover:text-zinc-50"
                        key={target.id}
                        onClick={() => splitTarget(target)}
                        role="menuitem"
                        type="button"
                      >
                        <span
                          aria-hidden="true"
                          className={cn(
                            "h-2 w-2 shrink-0 rounded-full",
                            statusDotClassNames[target.status],
                          )}
                        />
                        <span className="min-w-0 flex-1">
                          <span className="block truncate font-medium">
