export function TerminalWorkspaceContent({
  activeTab,
  contentInsetStyle,
  focusedPaneId,
  onClosePane,
  onCreateTerminal,
  onFocusPane,
  onOpenAiTool,
  onOpenConnection,
  onOpenLogs,
  onPaneCurrentCwdChange,
  onPaneOutputHistoryChange,
  onSplitPane,
  panesById,
  renderCustomTab,
  resolvedTheme,
  splitDropIndicator,
  tabs,
  terminalAppearance,
  terminalInset,
  workspacePaddingClass,
}: TerminalWorkspaceContentProps) {
  return (
    <div
      className={cn(
        "relative min-h-0 flex-1 transition-[margin-right] duration-200 ease-out",
        workspacePaddingClass,
      )}
      data-terminal-workspace-content
      style={contentInsetStyle}
    >
      {splitDropIndicator ? (
        <TerminalSplitDropOverlay indicator={splitDropIndicator} />
      ) : null}
      {tabs.length > 0 ? (
        tabs.map((tab) => {
          const active = tab.id === activeTab?.id;
          return (
            <div
              aria-hidden={!active || undefined}
              className={cn(
                "absolute min-h-0",
                active
                  ? "pointer-events-auto z-10"
                  : "pointer-events-none invisible z-0",
              )}
              key={tab.id}
              style={{ inset: terminalInset }}
            >
              {isTerminalSessionTab(tab) ? (
                <TerminalPaneLayout
                  focusedPaneId={active ? focusedPaneId : ""}
                  layout={tab.layout}
                  onClosePane={onClosePane}
                  onCurrentCwdChange={onPaneCurrentCwdChange}
                  onFocusPane={onFocusPane}
                  onOpenLogs={onOpenLogs}
                  onOutputHistoryChange={onPaneOutputHistoryChange}
                  onSplitPane={onSplitPane}
                  panesById={panesById}
                  resolvedTheme={resolvedTheme}
                  terminalAppearance={terminalAppearance}
                />
              ) : (
                renderCustomTab?.(tab, active) ?? (
                  <div className="kerminal-solid-surface flex h-full items-center justify-center rounded-2xl border text-sm text-zinc-500 dark:text-zinc-400">
                    此标签暂不可用。
                  </div>
                )
              )}
            </div>
          );
        })
      ) : (
        <TerminalEmptyState
          onCreateTerminal={onCreateTerminal}
          onOpenAiTool={onOpenAiTool}
          onOpenConnection={onOpenConnection}
        />
      )}
    </div>
  );
}

import type {
  MachineStatus,
  TerminalPane,
} from "../workspace/types";

export type BroadcastTargetMode = "focused" | "all" | "custom";

export interface BroadcastTargetOption {
  machineId: string;
  mode: TerminalPane["mode"];
  paneId: string;
  production: boolean;
  status: MachineStatus;
  subtitle: string;
  title: string;
}

export function createBroadcastTargetOption(
  pane: TerminalPane,
): BroadcastTargetOption {
  const subtitleParts = [
    pane.machineId,
    pane.status !== "online" ? pane.status : undefined,
    typeof pane.latencyMs === "number" ? `${pane.latencyMs}ms` : undefined,
  ].filter((part): part is string => Boolean(part));

  return {
    machineId: pane.machineId,
    mode: pane.mode,
    paneId: pane.id,
    production: Boolean(pane.remoteHostProduction),
    status: pane.status,
    subtitle: subtitleParts.join(" · "),
    title: pane.title,
  };
}

export function resolveBroadcastTargetPaneIds(
  mode: BroadcastTargetMode,
  targetOptions: BroadcastTargetOption[],
  focusedPaneId: string,
  customTargetPaneIds: string[],
) {
  if (mode === "focused") {
    return targetOptions.some((target) => target.paneId === focusedPaneId)
      ? [focusedPaneId]
      : [];
  }

  if (mode === "custom") {
    const validTargetPaneIds = new Set(
      targetOptions.map((target) => target.paneId),
    );
    return customTargetPaneIds.filter((paneId) =>
      validTargetPaneIds.has(paneId),
    );
  }

  return targetOptions.map((target) => target.paneId);
}

export function filterBroadcastTargetsByPaneIds<
  T extends { paneId: string },
>(targets: T[], paneIds: string[]) {
  const selectedPaneIds = new Set(paneIds);
  return targets.filter((target) => selectedPaneIds.has(target.paneId));
}

export function countProductionTargets(targets: BroadcastTargetOption[]) {
  return targets.filter((target) => target.production).length;
}

