describe("terminal split drop zones", () => {
  it("returns null when the pointer is outside the terminal content rect", () => {
    expect(resolveTerminalSplitDropZone(rect, { clientX: 9, clientY: 120 })).toBe(
      null,
    );
    expect(
      resolveTerminalSplitDropZone(rect, { clientX: 311, clientY: 120 }),
    ).toBe(null);
    expect(resolveTerminalSplitDropZone(rect, { clientX: 120, clientY: 19 })).toBe(
      null,
    );
    expect(
      resolveTerminalSplitDropZone(rect, { clientX: 120, clientY: 221 }),
    ).toBe(null);
  });

  it("resolves each edge hot zone", () => {
    expect(resolveTerminalSplitDropZone(rect, { clientX: 24, clientY: 120 })).toBe(
      "left",
    );
    expect(
      resolveTerminalSplitDropZone(rect, { clientX: 296, clientY: 120 }),
    ).toBe("right");
    expect(resolveTerminalSplitDropZone(rect, { clientX: 160, clientY: 34 })).toBe(
      "top",
    );
    expect(
      resolveTerminalSplitDropZone(rect, { clientX: 160, clientY: 206 }),
    ).toBe("bottom");
  });

  it("returns null for points inside the rect but outside all hot zones", () => {
    expect(
      resolveTerminalSplitDropZone(rect, { clientX: 160, clientY: 120 }),
    ).toBe(null);
  });

  it("clamps the inset so small terminal areas keep a center gap", () => {
    const smallRect = {
      bottom: 100,
      height: 100,
      left: 0,
      right: 100,
      top: 0,
      width: 100,
    };

    expect(
      resolveTerminalSplitDropZone(smallRect, { clientX: 39, clientY: 50 }),
    ).toBe("left");
    expect(
      resolveTerminalSplitDropZone(smallRect, { clientX: 50, clientY: 50 }),
    ).toBe(null);
    expect(
      resolveTerminalSplitDropZone(smallRect, { clientX: 61, clientY: 50 }),
    ).toBe("right");
  });

  it("chooses the closer edge when corner hot zones overlap", () => {
    expect(resolveTerminalSplitDropZone(rect, { clientX: 30, clientY: 28 })).toBe(
      "top",
    );
    expect(resolveTerminalSplitDropZone(rect, { clientX: 18, clientY: 42 })).toBe(
      "left",
    );
  });

  it("prefers left or right over top or bottom when corner distances tie", () => {
    expect(resolveTerminalSplitDropZone(rect, { clientX: 34, clientY: 44 })).toBe(
      "left",
    );
    expect(
      resolveTerminalSplitDropZone(rect, { clientX: 286, clientY: 44 }),
    ).toBe("right");
  });

  it("maps drop zones to terminal split directions", () => {
    const expected: Record<TerminalSplitDropZone, "horizontal" | "vertical"> = {
      bottom: "vertical",
      left: "horizontal",
      right: "horizontal",
      top: "vertical",
    };

    for (const [zone, direction] of Object.entries(expected)) {
      expect(terminalSplitDropZoneToDirection(zone as TerminalSplitDropZone)).toBe(
        direction,
      );
    }
  });
});

import type { TerminalSplitDirection } from "../workspace/types";

export type TerminalSplitDropZone = "left" | "right" | "top" | "bottom";

export interface TerminalSplitDropZonePoint {
  clientX: number;
  clientY: number;
}

export interface TerminalSplitDropZoneOptions {
  inset?: number;
}

type TerminalSplitDropZoneRect = Pick<
  DOMRectReadOnly,
  "bottom" | "height" | "left" | "right" | "top" | "width"
>;

const DEFAULT_HOT_ZONE_INSET = 96;
const MAX_HOT_ZONE_RATIO = 0.4;

const zonePriority: Record<TerminalSplitDropZone, number> = {
  left: 0,
  right: 1,
  top: 2,
  bottom: 3,
};

export function resolveTerminalSplitDropZone(
  rect: TerminalSplitDropZoneRect,
  point: TerminalSplitDropZonePoint,
  options: TerminalSplitDropZoneOptions = {},
): TerminalSplitDropZone | null {
  if (rect.width <= 0 || rect.height <= 0) {
    return null;
  }

  const { clientX, clientY } = point;
  if (
    clientX < rect.left ||
    clientX > rect.right ||
    clientY < rect.top ||
    clientY > rect.bottom
  ) {
    return null;
  }

  const requestedInset = Math.max(0, options.inset ?? DEFAULT_HOT_ZONE_INSET);
  const horizontalInset = Math.min(
    requestedInset,
    rect.width * MAX_HOT_ZONE_RATIO,
  );
  const verticalInset = Math.min(
    requestedInset,
    rect.height * MAX_HOT_ZONE_RATIO,
  );
  const candidates: Array<{
    distance: number;
    zone: TerminalSplitDropZone;
  }> = [];

  const leftDistance = clientX - rect.left;
  const rightDistance = rect.right - clientX;
  const topDistance = clientY - rect.top;
  const bottomDistance = rect.bottom - clientY;

  if (leftDistance <= horizontalInset) {
    candidates.push({ distance: leftDistance, zone: "left" });
  }
  if (rightDistance <= horizontalInset) {
    candidates.push({ distance: rightDistance, zone: "right" });
  }
  if (topDistance <= verticalInset) {
    candidates.push({ distance: topDistance, zone: "top" });
  }
  if (bottomDistance <= verticalInset) {
    candidates.push({ distance: bottomDistance, zone: "bottom" });
  }

  if (candidates.length === 0) {
    return null;
  }

  candidates.sort(
    (a, b) =>
      a.distance - b.distance || zonePriority[a.zone] - zonePriority[b.zone],
  );

  return candidates[0].zone;
}

export function terminalSplitDropZoneToDirection(
  zone: TerminalSplitDropZone,
): TerminalSplitDirection {
  return zone === "left" || zone === "right" ? "horizontal" : "vertical";
}

